sp_widget.client_script:
function ($scope,$http, spUtil,$rootScope) {
	var c = this;
	if (!c.options.table)
		return;

	spUtil.recordWatch($scope, c.options.table, c.options.filter);
	// STRY0114448 - adding additional parameters
	c.params = {
		'filter' : c.options.filter,
		'sp_page_dv' : c.options.sp_page_dv,
		'table' : c.options.table,
		'title' : c.options.title,
		'd' : c.options.d,
		'o' : c.options.o,
		'field_list': c.options.field_list,
		'glyph' : c.options.glyph
	};

	c.getData = function(){
		$rootScope.$broadcast('countPanelClicked', c.params);
	}

}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.8.0 | 2022-08-24 | raj | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed) 
//                                         Cloned new copy of widget b/c Tasker Count changed too much to support his use case
// 2.8.0 | 2022-08-24 | raj  | DFCT0011211 - DTLV page should NOT display white color widgets for the "On Time", "Warning" & "Critical" under the Subtasks by Status section header
//                                         Changes made in Server Script, Client Controller and HTML
// 2.8.0 | 2022-08-24 | raj  | DFCT0011169 - Stretch: Empty data displays under "Activity Log" modal
//                                         Changes made in Server Script, Client Controller and HTML
//------------------------------------------------------------------------------------------------------------------------
.count {
	margin-top: 0px;
}

div {
	cursor: pointer;
}

.count.primary,
.text-primary {
	color: $brand-primary-text;
}

.count.info,
.text-info {
	color: $brand-info-text;
}

.count.sucess,
.text-sucess {
	color: $brand-success-text;
}

.count.warning,
.text-warning {
	color: $brand-warning-text;
}

.count.danger,
.text-danger {
	color: $brand-danger-text;
}

