// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: COUNT
// COMPANY: DISCOVER TECHNOLOGIES
// 2.8.0 | 2022-08-24 | raj | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed) 
//                                         Cloned new copy of widget b/c Tasker Count changed too much to support his use case
// 2.8.0 | 2022-08-24 | raj  | DFCT0011211 - DTLV page should NOT display white color widgets for the "On Time", "Warning" & "Critical" under the Subtasks by Status section header
//                                         Changes made in Server Script, Client Controller and HTML
// 2.8.0 | 2022-08-24 | raj  | DFCT0011169 - Stretch: Empty data displays under "Activity Log" modal
//                                         Changes made in Server Script, Client Controller and HTML
// 2.8.5 | 2024-12-04 | raj | ServiceNow Certification addEncodedQuery recommendation
//
(function () {
	if (!options.table)
		return;

	data.filter = options.filter || 'sys_id!=NULL';
	data.o = options.order_by || 'created';
	data.d = options.order_direction || 'DESC';
	data.field_list = options.field_list || '';
	//data.color = c.options.color || 'primary';

	var a = new GlideAggregate(options.table);
	// ServiceNow Certification update - Tasker 2.8.5
	a.addEncodedQuery(GlideStringUtil.escapeQueryTermSeparator(data.filter));
	a.addAggregate("COUNT");
	a.query();
	var count=0;
	if(a.next()){
		count = a.getAggregate("COUNT");
	}
	data.count = count;	
})();
